    }

    #[test]
    fn test_with_model() {
        let provider = WhisperStt::with_model(
            Some(Secret::new("key".into())),
            Some("whisper-large-v3".into()),
        );
        assert_eq!(provider.model, "whisper-large-v3");
    }

    #[test]
    fn test_whisper_response_parsing() {
        let json = r#"{
            "text": "Hello, how are you?",
