/// Live TTS service that delegates to voice providers.
/// Reads fresh config on each operation to pick up changes.
#[cfg(feature = "voice")]
pub struct LiveTtsService {
    _marker: std::marker::PhantomData<()>,
}

#[cfg(feature = "voice")]
impl std::fmt::Debug for LiveTtsService {
